const body = $json.body || $json;

function clean(v) {
  if (v === undefined || v === null) return '';
  return String(v).trim();
}

const applicantName = clean(body.applicantName);
const applicantEmail = clean(body.applicantEmail).toLowerCase();
const phone = clean(body.phone);
const businessName = clean(body.businessName);
const routeDetected = clean(body.routeDetected) || 'Unknown';
const source = clean(body.source) || 'DAC Applicant Automation';
const emailSubject = clean(body.emailSubject);
const revenue = clean(body.revenue);
const bankType = clean(body.bankType);
const status = clean(body.status) || 'Submission started';
const firstReplySent = body.firstReplySent === true || String(body.firstReplySent).toLowerCase() === 'true';
const notes = clean(body.notes);
const gmailMessageId = clean(body.messageId);
const gmailThreadId = clean(body.threadId);

let priority = 'medium';
if (/incomplete|needs action|missing/i.test(status)) priority = 'high';
if (/funded|closed/i.test(status)) priority = 'low';
if (/submission started/i.test(status) && firstReplySent) priority = 'high';

let nextStep = 'Review route';
if (firstReplySent) nextStep = 'Waiting on applicant reply';
if (/incomplete|missing/i.test(status)) nextStep = 'Need docs';
if (/bank/i.test(status)) nextStep = 'Need bank link';
if (/review|underwriting/i.test(status)) nextStep = 'Await provider review';
if (/other options/i.test(status)) nextStep = 'Send other options';
if (/funded/i.test(status)) nextStep = 'None';

let dealStage = 'qualifiedtobuy';
if (/incomplete|missing|waiting/i.test(status)) dealStage = 'presentationscheduled';
if (/review|underwriting/i.test(status)) dealStage = 'decisionmakerboughtin';
if (/funded/i.test(status)) dealStage = 'closedwon';
if (/dead|lost|withdrawn|not now|closed|client file closed/i.test(status)) dealStage = 'closedlost';

const routeShort = /giggle/i.test(routeDetected) ? 'Giggle' : /bankbreezy/i.test(routeDetected) ? 'BankBreezy' : 'Unknown';
const dealName = `${applicantName} | DAC Applicant | ${routeShort}`;

const description = [
  `Source: ${source}`,
  `Original email subject: ${emailSubject}`,
  `Applicant email: ${applicantEmail}`,
  `Owner phone: ${phone}`,
  `Business name: ${businessName || 'Not yet confirmed'}`,
  `Route detected: ${routeDetected}`,
  `Revenue: ${revenue || 'Unknown'}`,
  `Bank type: ${bankType || 'Unknown'}`,
  `Current blocker: ${/incomplete|missing/i.test(status) ? 'Application incomplete' : 'None confirmed yet'}`,
  `Last meaningful update: ${firstReplySent ? 'First reply sent; awaiting response' : status}`,
  `Notes: ${notes || 'Auto-created from applicant intake workflow.'}`,
  `Gmail Message ID: ${gmailMessageId}`,
  `Gmail Thread ID: ${gmailThreadId}`
].join('\n');

return [{
  applicantName,
  applicantEmail,
  phone,
  businessName,
  routeDetected,
  routeShort,
  source,
  emailSubject,
  revenue,
  bankType,
  status,
  firstReplySent,
  notes,
  gmailMessageId,
  gmailThreadId,
  priority,
  nextStep,
  dealStage,
  dealName,
  description,
  pipeline: 'default',
  dealType: 'newbusiness',
  hubspotOwnerId: '41491296'
}];

const results = $json.results || [];
const contact = results[0] || null;
return [{
  ...$('Normalize Applicant Payload').first().json,
  contactFound: !!contact,
  contactId: contact ? contact.id : null,
  contactRecord: contact
}];

const dealResults = $json.results || [];
const applicantEmail = $('Set Contact Match').first().json.applicantEmail;
const applicantName = $('Set Contact Match').first().json.applicantName;

let exactMatch = null;
for (const d of dealResults) {
  const desc = (d.properties?.description || '').toLowerCase();
  const name = (d.properties?.dealname || '').toLowerCase();
  if (desc.includes(applicantEmail.toLowerCase()) || name.includes(applicantName.toLowerCase())) {
    exactMatch = d;
    break;
  }
}

return [{
  ...$('Set Contact Match').first().json,
  dealFound: !!exactMatch,
  dealId: exactMatch ? exactMatch.id : null,
  dealRecord: exactMatch,
  rawDealSearchResults: dealResults
}];

const source = $input.first().json;
const normalized = $('Apply Dedupe Logic').first().json;

const dealId = source.id || normalized.dealId;

return [{
  ...normalized,
  finalDealId: dealId,
  actionTaken: normalized.dealFound ? 'updated' : 'created'
}];

const data = $json;
const now = new Date();

function addDays(days) {
  const d = new Date(now);
  d.setDate(d.getDate() + days);
  d.setHours(12,0,0,0);
  return d.toISOString();
}

const tasks = [];

if (data.firstReplySent) {
  tasks.push({ subject: `${data.applicantName} — Follow-up #2 (Group + Resources)`, body: 'Send Email 2: invite to Funding Applicants Hub + resources + secondary engagement path.', due: addDays(2) });
  tasks.push({ subject: `${data.applicantName} — Follow-up #3 (Alt options nudge)`, body: 'Send Email 3: soft nudge + offer alternative funding paths.', due: addDays(4) });
  tasks.push({ subject: `${data.applicantName} — Follow-up #4 (Simplify + friction removal)`, body: 'Send Email 4: simplify process + reduce friction + quick reply prompt.', due: addDays(7) });
  tasks.push({ subject: `${data.applicantName} — Final follow-up / close loop`, body: 'Send Email 5: final bump + open loop + soft exit.', due: addDays(12) });
} else {
  tasks.push({ subject: `${data.applicantName} — Send first reply`, body: 'Send first follow-up email to applicant.', due: addDays(0) });
  tasks.push({ subject: `${data.applicantName} — Follow-up #2 (Post-first-reply check-in)`, body: 'Follow up after first reply if no response.', due: addDays(2) });
}

return tasks.map(t => ({
  ...data,
  taskSubject: t.subject,
  taskBody: t.body,
  taskDue: t.due
}));
